/* Combined site JS (lightly compacted) */
// navbar.js (template + helper)
function calcPrefix(){const path=globalThis.location.pathname||'';if(path.includes('/pages/')||path.includes('\\pages\\'))return '../';return ''}const _p=calcPrefix();const navbarTemplate=`
  <header class="navbar">
    <div class="logo">
      <a href="${_p}index.html">
        <img src="${_p}assets/images/logoScuola.webp" alt="Logo MU" width="94" height="94" style="height: 60px; width: auto" />
      </a>
      <span>Monsters University</span>
    </div>
    <button class="hamburger" aria-label="Apri menu">
      <span></span>
      <span></span>
      <span></span>
    </button>
    <nav>
      <ul class="nav-links">
        <li><a href="${_p}index.html" data-i18n="nav_home">Home</a></li>
        <li><a href="${_p}pages/nostriCorsi.html" data-i18n="nav_corsi">I Nostri Corsi</a></li>
        <li><a href="${_p}pages/comeRaggiungerci.html" data-i18n="nav_raggiungerci">Come Raggiungerci</a></li>
            <li class="nav-lang">
              <div class="lang-toggle" role="button" tabindex="0" aria-haspopup="true" aria-expanded="false">
                <img class="flag-img" src="${_p}assets/images/flags/it.svg" alt="IT" aria-hidden="true"><span class="visually-hidden">Italiano</span>
              </div>
              <div class="lang-dropdown">
                <button class="lang-option" data-lang="it" data-flag="${_p}assets/images/flags/it.svg" data-label="Italian"><img class="flag-img" src="${_p}assets/images/flags/it.svg" alt="Italian"><span class="lang-label">Italian</span></button>
                <button class="lang-option" data-lang="en" data-flag="${_p}assets/images/flags/gb.svg" data-label="English (GB)"><img class="flag-img" src="${_p}assets/images/flags/gb.svg" alt="English (GB)"><span class="lang-label">English (GB)</span></button>
              </div>
            </li>
      </ul>
    </nav>
  </header>
`;
const menuSmartphoneTemplate=`
  <ul class="menuSmartphone">
    <li class="menu-lang">
      <div class="lang-toggle" role="button" tabindex="0" aria-haspopup="true" aria-expanded="false">
        <span class="lang-left"><img class="flag-img" src="${_p}assets/images/flags/it.svg" alt="IT" aria-hidden="true"><span class="lang-current-name">Italiano</span></span>
        <span class="lang-right"><span class="caret">▾</span></span>
      </div>
      <div class="lang-dropdown">
        <button class="lang-option" data-lang="it" data-flag="${_p}assets/images/flags/it.svg" data-label="Italiano"><img class="flag-img" src="${_p}assets/images/flags/it.svg" alt="Italiano"><span class="lang-label">Italiano</span></button>
        <button class="lang-option" data-lang="en" data-flag="${_p}assets/images/flags/gb.svg" data-label="English (GB)"><img class="flag-img" src="${_p}assets/images/flags/gb.svg" alt="English (GB)"><span class="lang-label">English (GB)</span></button>
      </div>
    </li>
    <li class="menu-divider"></li>
    <li><a href="${_p}index.html" data-i18n="nav_home">Home</a></li>
    <li><a href="${_p}pages/nostriCorsi.html" data-i18n="nav_corsi">I Nostri Corsi</a></li>
    <li><a href="${_p}pages/comeRaggiungerci.html" data-i18n="nav_raggiungerci">Come Raggiungerci</a></li>
  </ul>
`;

// customNavbar.js (jQuery)
document.addEventListener('DOMContentLoaded',function(){
  if(window.jQuery){
    (function($){
      $(document).ready(function(){
        $('.hamburger').click(function(){
          $('.menuSmartphone').toggleClass('open');
          $(this).toggleClass('open');
          var expanded=$(this).hasClass('open')?'true':'false';
          $(this).attr('aria-expanded',expanded);
        });
      });
    })(jQuery);
  }
});

// footer.js
document.addEventListener("DOMContentLoaded",function(){const annoCorrente=new Date().getFullYear();const footer=document.createElement("footer");footer.className="site-footer";footer.innerHTML=`\n        <p>© ${annoCorrente} <span data-i18n="footer_testo">Monsters University — Tutti i diritti riservati</span></p>\n    `;document.body.appendChild(footer)});

// cambioLingua.js (template)
const langSelectorTemplate=`
  <div id="lang-selector">
    <button id="lang-toggle">🌐 <span id="current-lang">IT</span></button>
    <div id="lang-dropdown">
      <button class="lang-option" data-lang="it" data-i18n="lang_it">Italiano</button>
      <button class="lang-option" data-lang="en" data-i18n="lang_en">English</button>
    </div>
  </div>
`;

// caricaNavBar.js
document.addEventListener("DOMContentLoaded",function(){const navbarPlaceholder=document.getElementById("navbar-placeholder");if(navbarPlaceholder){navbarPlaceholder.outerHTML=navbarTemplate}});const menuSmartphonePlaceholder=document.getElementById("menu-smartphone-placeholder");if(menuSmartphonePlaceholder){menuSmartphonePlaceholder.outerHTML=menuSmartphoneTemplate}

// lang.js (assemble translations) - expects translationsIT/translationsEN to exist
const translations={it:translationsIT,en:translationsEN};

// langService.js (language utils)
function getLang(){return localStorage.getItem("lang")||"it"}
function applyLang(lang){document.querySelectorAll("[data-i18n]").forEach(function(el){const key=el.dataset.i18n;if(translations[lang]&&translations[lang][key]){el.textContent=translations[lang][key]}else{console.warn("Chiave mancante nel dizionario:",key,"— lingua:",lang)}});document.querySelectorAll('.current-lang').forEach(function(el){el.textContent=lang.toUpperCase()});const opt=document.querySelector('.lang-option[data-lang="'+lang+'"]');const label=opt?(opt.dataset.label||opt.textContent.trim()):'';const flagPath=opt?(opt.dataset.flag||''):'';document.querySelectorAll('.lang-toggle').forEach(function(toggle){const srEl=toggle.querySelector('.visually-hidden');const imgEl=toggle.querySelector('.flag-img');const currentNameEl=toggle.querySelector('.lang-current-name');if(srEl&&label)srEl.textContent=label;if(currentNameEl&&label)currentNameEl.textContent=label;if(imgEl&&flagPath)imgEl.src=flagPath});document.querySelectorAll('.lang-option').forEach(function(opt){const lbl=opt.dataset.label||'';const visibleLabel=opt.querySelector('.lang-label');if(visibleLabel)visibleLabel.textContent=lbl});localStorage.setItem("lang",lang);document.documentElement.setAttribute("lang",lang)}
document.addEventListener("DOMContentLoaded",function(){applyLang(getLang());function closeAllLangDropdowns(){document.querySelectorAll('.lang-dropdown').forEach(function(d){d.classList.remove('open')});document.querySelectorAll('.lang-toggle').forEach(function(t){t.setAttribute('aria-expanded','false')})}document.querySelectorAll('.lang-toggle').forEach(function(toggle){toggle.addEventListener('click',function(e){e.stopPropagation();const dropdown=this.nextElementSibling;if(!dropdown)return;const isOpen=dropdown.classList.toggle('open');this.setAttribute('aria-expanded',isOpen?'true':'false');})});document.addEventListener('click',function(){closeAllLangDropdowns()});document.querySelectorAll('.lang-option').forEach(function(btn){btn.addEventListener('click',function(e){e.stopPropagation();const lang=this.dataset.lang;applyLang(lang);closeAllLangDropdowns()})})});

/* End of combined site JS */
